fun isTrapezoid(a: Array<Long>, b: Array<Long>, c: Array<Long>, d: Array<Long>): Boolean {
    val slopes = mutableListOf<Pair<Double, Boolean>>()
    // Check all pairs of sides for parallel sides
    val abSlope = calculateSlope(a, b)
    val acSlope = calculateSlope(a, c)
    val adSlope = calculateSlope(a, d)
    val bcSlope = calculateSlope(b, c)
    val bdSlope = calculateSlope(b, d)
    val cdSlope = calculateSlope(c, d)

    // Check all possible pairs of sides for parallelism
    if (abSlope == cdSlope && abSlope != Double.POSITIVE_INFINITY) {
        return true
    }
    if (acSlope == bdSlope && acSlope != Double.POSITIVE_INFINITY) {
        return true
    }
    if (adSlope == bcSlope && adSlope != Double.POSITIVE_INFINITY) {
        return true
    }
    // Handle vertical lines (infinite slope)
    if (abSlope == Double.POSITIVE_INFINITY && cdSlope == Double.POSITIVE_INFINITY) {
        return true
    }
    if (acSlope == Double.POSITIVE_INFINITY && bdSlope == Double.POSITIVE_INFINITY) {
        return true
    }
    if (adSlope == Double.POSITIVE_INFINITY && bcSlope == Double.POSITIVE_INFINITY) {
        return true
    }
    return false
}

fun calculateSlope(p1: Array<Long>, p2: Array<Long>): Double {
    val (x1, y1) = p1
    val (x2, y2) = p2
    if (x1 == x2) {
        return Double.POSITIVE_INFINITY
    }
    return (y2 - y1).toDouble() / (x2 - x1).toDouble()
}
