    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val x1 = points[i][0]
            val y1 = points[i][1]
            val x2 = points[j][0]
            val y2 = points[j][1]

            // Calculate the slope as a reduced fraction to avoid floating point precision issues
            val dx = x2 - x1
            val dy = y2 - y1
            val g = gcd(dx, dy)
            val reducedDx = dx / g
            val reducedDy = dy / g

            // Use a string to represent the slope direction (handles vertical and horizontal lines)
            val slopeKey = if (dx == 0L) "inf" 
                           else if (dy == 0L) "0" 
                           else "$reducedDx,$reducedDy"

            slopeMap.getOrPut(slopeKey) { mutableListOf() }.add(i to j)
        }
    }

    // For each slope, check all pairs of line segments to form trapezoids
    for ((_, segments) in slopeMap) {
        if (segments.size < 2) continue
        // Check all pairs of segments with the same slope
        for (i in 0 until segments.size) {
            val (a, b) = segments[i]
            for (j in i + 1 until segments.size) {
                val (c, d) = segments[j]
                // Ensure all four points are distinct
                val pointsSet = setOf(a, b, c, d)
                if (pointsSet.size == 4) {
                    count++
                }
            }
        }
    }

    // Since each trapezoid is counted once for each pair of parallel sides, we need to divide by the number of parallel pairs
    // But since the problem counts trapezoids with at least one pair of parallel sides, we need to avoid overcounting
    // So we need to adjust the count by considering trapezoids with two pairs of parallel sides (parallelograms)
    // We will subtract the number of parallelograms once (since they are counted twice in the initial count)
    val parallelogramCount = countParallelograms(points)
    return count - parallelogramCount
}

private fun countParallelograms(points: Array<Array<Long>>): Long {
    val n = points.size
    var count = 0L
    val midPoints = mutableMapOf<Pair<Long, Long>, Int>()

    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val x1 = points[i][0]
            val y1 = points[i][1]
            val x2 = points[j][0]
            val y2 = points[j][1]
            val midX = x1 + x2
            val midY = y1 + y2
            val key = midX to midY
            count += midPoints.getOrDefault(key, 0)
            midPoints[key] = midPoints.getOrDefault(key, 0) + 1
        }
    }
    return count
}

private fun gcd(a: Long, b: Long): Long {
    var x = a
    var y = b
    while (y != 0L) {
        val temp = y
        y = x % y
        x = temp
    }
    return x
}
