                val dy1 = y2 - y1
                val dx2 = x3 - x1
                val dy2 = y3 - y1

                // Cross product to check if points are collinear
                if (dx1 * dy2 == dx2 * dy1) continue

                // Calculate slope of (i,j) and (i,k)
                val slope1 = simplifyFraction(dy1, dx1)
                val slope2 = simplifyFraction(dy2, dx2)

                val key = if (slope1 == slope2) "parallel" else "non-parallel"
                if (!slopeMap.containsKey(key)) {
                    slopeMap[key] = mutableListOf()
                }
                slopeMap[key]?.add(Pair(i, k))
            }

            val parallelLines = slopeMap["parallel"] ?: continue
            val nonParallelLines = slopeMap["non-parallel"] ?: continue

            // Group non-parallel lines by their slope to find pairs with same slope
            val nonParallelSlopeGroups = mutableMapOf<String, MutableList<Pair<Int, Int>>>()
            for (line in nonParallelLines) {
                val (a, b) = line
                val (x1, y1) = points[a]
                val (x2, y2) = points[b]
                val dx = x2 - x1
                val dy = y2 - y1
                val slope = simplifyFraction(dy, dx)
                val key = "$slope"
                if (!nonParallelSlopeGroups.containsKey(key)) {
                    nonParallelSlopeGroups[key] = mutableListOf()
                }
                nonParallelSlopeGroups[key]?.add(line)
            }

            // For each group of non-parallel lines with same slope, count possible trapezoids
            for ((_, group) in nonParallelSlopeGroups) {
                if (group.size >= 2) {
                    // Number of ways to choose 2 lines from this group
                    val m = group.size
                    count += m * (m - 1) / 2
                }
            }
        }
    }

    // Since each trapezoid is counted twice (once for each pair of parallel sides), divide by 2
    return count / 2
}

fun simplifyFraction(dy: Long, dx: Long): String {
    if (dx == 0L) return "inf"
    if (dy == 0L) return "0"

    val gcd = gcd(dy, dx)
    val simplifiedDy = dy / gcd
    val simplifiedDx = dx / gcd

    // Ensure consistent representation (e.g., 1/-2 becomes -1/2)
    val sign = if (simplifiedDx < 0) -1 else 1
    return "${sign * simplifiedDy}/${sign * simplifiedDx}"
}

