                val dx1 = x2 - x1
                val dy1 = y2 - y1
                val dx2 = x3 - x1
                val dy2 = y3 - y1

                // Cross product to check if collinear
                if (dx1 * dy2 == dx2 * dy1) continue

                // Calculate slope as reduced fraction to avoid floating point precision issues
                val (slopeNum, slopeDen) = if (dx1 == 0L) {
                    // Vertical line, use a special key
                    "inf" to 1
                } else {
                    val g = gcd(dy1, dx1)
                    (dy1 / g) to (dx1 / g)
                }
                val slopeKey = "$slopeNum,$slopeDen"

                // Calculate the slope of (i,k)
                val (slopeNum2, slopeDen2) = if (dx2 == 0L) {
                    "inf" to 1
                } else {
                    val g = gcd(dy2, dx2)
                    (dy2 / g) to (dx2 / g)
                }
                val slopeKey2 = "$slopeNum2,$slopeDen2"

                // Check if (i,k) is parallel to any existing line in the map
                if (slopeKey2 in slopeMap) {
                    for ((a, b) in slopeMap[slopeKey2]!!) {
                        // Check if the four points are not collinear and form a quadrilateral
                        if (!areCollinear(points[i], points[j], points[k]) && 
                            !areCollinear(points[i], points[j], points[a]) &&
                            !areCollinear(points[i], points[k], points[a]) &&
                            !areCollinear(points[j], points[k], points[a])) {
                            count++
                        }
                    }
                }

                // Add the line (i,j) to the map with point k
                if (slopeKey !in slopeMap) {
                    slopeMap[slopeKey] = mutableListOf()
                }
                slopeMap[slopeKey]?.add(Pair(j, k))
            }
        }
    }

    // Each trapezoid is counted 4 times (once for each pair of parallel sides)
    return count / 4
}

fun gcd(a: Long, b: Long): Long {
    var x = a
    var y = b
    while (y != 0L) {
        val temp = y
        y = x % y
        x = temp
    }
    return x
}

fun areCollinear(a: Array<Long>, b: Array<Long>, c: Array<Long>): Boolean {
    val (x1, y1) = a
    val (x2, y2) = b
    val (x3, y3) = c
    return (y2 - y1) * (x3 - x1) == (y3 - y1) * (x2 - x1)
}
